import{_ as i,c as t,o as r,ag as a}from"./chunks/framework.091VdYs-.js";const m=JSON.parse('{"title":"Projekte","description":"","frontmatter":{"sidebar":true},"headers":[],"relativePath":"projekte/index.md","filePath":"projekte/index.md"}'),n={name:"projekte/index.md"};function s(d,e,c,l,o,u){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="projekte" tabindex="-1">Projekte <a class="header-anchor" href="#projekte" aria-label="Permalink to &quot;Projekte&quot;">​</a></h1><p>Neben dem Beruf baue ich Software – manchmal aus Neugier, manchmal aus Frustration mit existierenden Lösungen, manchmal weil eine Idee keine Ruhe lässt. Die Projekte auf dieser Seite sind über mehrere Jahre entstanden und spiegeln wider, womit ich mich außerhalb meiner regulären Arbeit beschäftige.</p><p>Einige davon sind aktiv in Betrieb, andere befinden sich in der Entwicklung. Allen gemeinsam ist, dass ich sie mit denselben Maßstäben gebaut habe, die ich auch beruflich anlege: ordentlicher Code, dokumentierte Entscheidungen, nachvollziehbare Architektur.</p><hr><a href="/projekte/bewerber-schmiede" class="project-card"><div class="card-title">Bewerber-Schmiede.de</div><div class="card-meta">Web-Anwendung · In Betrieb</div><div class="card-desc">Ein Tool zur Analyse von Lebensläufen. Gibt strukturiertes Feedback zu Vollständigkeit, Formulierungen und häufigen Schwachstellen. Vollständig mit Claude Code als KI-Entwicklungspartner entwickelt – inklusive CI/CD-Pipeline, automatisierter Tests und End-to-End-Tests.</div></a><a href="/projekte/dailydev" class="project-card"><div class="card-title">DailyDev</div><div class="card-meta">VitePress · Raspberry Pi · Selbst gehostet</div><div class="card-desc">Ein persönliches Lernsystem mit 584 ausgearbeiteten Themen rund um Softwareentwicklung. Läuft auf einem Raspberry Pi und liefert täglich automatisch einen Beitrag aufs Mobiltelefon – Konzepte, Fragen, Codebeispiele. Nutzt die gesamte Breite von VitePress als Framework.</div></a><a href="/projekte/tinybill" class="project-card"><div class="card-title">TinyBill</div><div class="card-meta">Web-Anwendung · In Betrieb · tinybill.de</div><div class="card-desc">Ein kostenloser Dokumentengenerator für Rechnungen, Angebote und Geschäftsdokumente. Entstanden aus zwei Jahren intensiver Arbeit mit E-Rechnungen bei der Infokom GmbH. Version 1 läuft produktiv, Version 2 wird in Kotlin mit API-first Ansatz neu aufgebaut.</div></a><a href="/projekte/shopitech" class="project-card"><div class="card-title">Shopitech – Web-Projekte</div><div class="card-meta">Kundenprojekte · Verschiedene Technologien</div><div class="card-desc">Einige ausgewählte Web-Projekte, die ich für Kunden gebaut habe: ein Handwerker-Service, eine Restaurant-Website, ein Hausnotruf-Dienst und weitere. Jedes Projekt hat eigene technische Anforderungen mitgebracht. Zuletzt habe ich die eigene Unternehmensseite von Next.js auf Framer migriert.</div></a><a href="/projekte/daily-pi-poetry" class="project-card"><div class="card-title">daily-pi-poetry</div><div class="card-meta">Raspberry Pi · Lokales Sprachmodell · Open Source</div><div class="card-desc">Ein lokales Sprachmodell auf dem Raspberry Pi, das täglich automatisch ein kurzes Gedicht generiert – ohne Cloud, ohne API, ohne externe Abhängigkeit. Ein Experiment zur Frage, was auf einem kleinen ARM-Gerät zur Laufzeit möglich ist.</div></a><a href="/projekte/merkelfy" class="project-card"><div class="card-title">Merkelfy</div><div class="card-meta">Spaßprojekt · merkelfy.dev-arts.de</div><div class="card-desc">Ein kleines Projekt ohne ernsten Hintergrund. Manchmal baut man etwas einfach weil es Spaß macht und nicht jedes Vorhaben einen business case braucht.</div></a>',10)])])}const p=i(n,[["render",s]]);export{m as __pageData,p as default};
